using Android.Content;
using Android.Util;
using SkiaSharp.Views.Android;

namespace Repro;

public class CircularGauge : SKCanvasView
{
    public CircularGauge(Context context) : base(context) { }
    public CircularGauge(Context context, IAttributeSet attrs) : base(context, attrs) { }

    protected override void OnSizeChanged(int w, int h, int oldw, int oldh)
    {
        base.OnSizeChanged(w, h, oldw, oldh);
    }
}

public class SemiCircularGauge : SKCanvasView
{
    public SemiCircularGauge(Context context) : base(context) { }
    public SemiCircularGauge(Context context, IAttributeSet attrs) : base(context, attrs) { }

    protected override void OnSizeChanged(int w, int h, int oldw, int oldh)
    {
        base.OnSizeChanged(w, h, oldw, oldh);
    }
}
